// âŒ BAD - public delegate field lets anyone invoke or clear subscribers
public class OrderService {
    public Action<int>? OrderShipped;
    public void Ship(int id) { OrderShipped(id); } // crash if null
}

// âœ… GOOD - event restricts external code; ?.Invoke is null-safe
public class OrderService {
    public event EventHandler<int>? OrderShipped;
    public void Ship(int id) {
        // process order...
        OrderShipped?.Invoke(this, id);
    }
}
var svc = new OrderService();
svc.OrderShipped += (_, id) => Console.WriteLine($"Order {id} shipped");
svc.Ship(42);

