// âœ… GOOD - generic with constraint; type-safe, no casting
public class Repository<T> where T : class, IEntity {
    private readonly AppDbContext _db;
    public Repository(AppDbContext db) => _db = db;
    public Task<T?> GetByIdAsync(int id) => _db.Set<T>().FindAsync(id).AsTask();
    public void Add(T entity) => _db.Set<T>().Add(entity);
}

// âŒ BAD - ToList() materialises the whole table, then filters in memory
var bad = db.Orders.ToList().Where(o => o.Status == OrderStatus.Shipped);

// âœ… GOOD - Where on IQueryable translates to SQL WHERE clause
var topCustomers = db.Orders
    .Where(o => o.Status == OrderStatus.Shipped)
    .GroupBy(o => o.CustomerId)
    .Select(g => new {
        CustomerId = g.Key,
        TotalSpend = g.Sum(o => o.Total),
        OrderCount = g.Count()
    })
    .OrderByDescending(x => x.TotalSpend)
    .Take(10)
    .ToList();

// âŒ BAD - long if/else chain with manual casting
string Describe(Shape shape) {
    if (shape is Circle) { var c = (Circle)shape; return $"Circle r={c.Radius}"; }
    else if (shape is Rectangle) { return "Rect"; }
    else return "Unknown";
}

// âœ… GOOD - switch expression: exhaustive, no casts, property patterns
string Describe(Shape shape) => shape switch {
    Circle { Radius: > 100 } c => $"Large circle r={c.Radius}",
    Circle c                   => $"Circle r={c.Radius}",
    Rectangle { Width: var w, Height: var h } when w == h => $"Square {w}x{h}",
    Rectangle r                => $"Rect {r.Width}x{r.Height}",
    null                       => "null",
    _                          => "Unknown shape"
};

