// âŒ BAD - verbose block body for trivially simple members
public class Invoice {
    public decimal SubTotal { get; }
    public decimal Tax { get; }
    public decimal Total { get { return SubTotal + Tax; } }
    public override string ToString() { return $"Invoice {Total:C}"; }
}

// âœ… GOOD - expression-bodied members: concise, readable
public class Invoice {
    public decimal SubTotal { get; }
    public decimal Tax { get; }
    public Invoice(decimal sub, decimal tax) => (SubTotal, Tax) = (sub, tax);
    public decimal Total => SubTotal + Tax;
    public override string ToString() => $"Invoice {Total:C}";
}

